import sys
from functools import lru_cache
input = sys.stdin.readline
sys.setrecursionlimit(500000)

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # prev is encoded as index: n means -1 (initial), otherwise a[prev_idx] was last taken
    # But prev can only be a[l-1] or a[r+1] at state (l,r)
    # Encode: prev_side: 0 = initial(-1), 1 = left end taken last (prev=a[l-1]), 2 = right end taken last (prev=a[r+1])
    # Actually store prev as index into extended array

    a_ext = [-1] + a  # a_ext[0] = -1, a_ext[i] = a[i-1]

    @lru_cache(maxsize=None)
    def dp(l, r, prev_val):
        # returns True if current player wins
        if l > r:
            return False
        can_left = a[l] > prev_val
        can_right = a[r] > prev_val

        if not can_left and not can_right:
            return False

        moves = []
        if can_left:
            moves.append(not dp(l+1, r, a[l]))
        if can_right and r != l:
            moves.append(not dp(l, r-1, a[r]))
        elif can_right and r == l:
            moves.append(True)  # takes last element, wins

        return any(moves)

    # prev_val must be hashable and comparable; use -1 as initial
    if dp(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

